object Solution { def revenue_stats_by_region(customers: Seq[Map[String, Any]], orders: Seq[Map[String, Any]]): Map[String, Map[String, Int]] = { val regionOf = customers.map(c => asInt(c("id")) -> c("region").toString).toMap; val stats = scala.collection.mutable.Map[String, scala.collection.mutable.Map[String, Int]](); for (order <- orders; region <- regionOf.get(asInt(order("customer_id")))) { val bucket = stats.getOrElseUpdate(region, scala.collection.mutable.Map("total" -> 0, "count" -> 0)); bucket("total") += asInt(order("amount")); bucket("count") += 1 }; stats.map { case (k, v) => k -> v.toMap }.toMap }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
